// tripHeaderStyle returns a safe inline style for the trip cover image.
// Only paths under uploads/ are allowed to prevent CSS injection.
func tripHeaderStyle(url string) string {
	if !strings.HasPrefix(url, "/uploads/") {
		return ""
	}
	return "background-image: linear-gradient(to bottom, rgba(0,0,0,0.25) 0%, rgba(0,0,0,0.65) 100%), url(" + url + "); background-size: cover; background-position: center;"
}

// legHeaderStyle returns a safe inline style for a leg cover image.
func legHeaderStyle(url string) string {
	if !strings.HasPrefix(url, "/uploads/") {
		return ""
	}
	return "background-image: linear-gradient(to bottom, rgba(0,0,0,0.45) 0%, rgba(0,0,0,0.7) 100%), url(" + url + "); background-size: cover; background-position: center;"
}

// phraseGroup is used by the phrasebook template to group phrases by category.
type phraseGroup struct {
	Category string
	Phrases  []domain.Phrase
}

// groupPhrasesByCategory preserves the original ordering of categories as they
// first appear, while collecting all phrases of the same category together.
func groupPhrasesByCategory(phrases []domain.Phrase) []phraseGroup {
	var groups []phraseGroup
	seen := map[string]int{}
	for _, p := range phrases {
		cat := p.Category
		if cat == "" {
			cat = "General"
		}
		if idx, ok := seen[cat]; ok {
			groups[idx].Phrases = append(groups[idx].Phrases, p)
		} else {
			seen[cat] = len(groups)
			groups = append(groups, phraseGroup{Category: cat, Phrases: []domain.Phrase{p}})
		}
	}
	return groups
}

